begin;
create table if not exists public.notes(id uuid primary key default gen_random_uuid(),workspace_id uuid not null references public.workspaces(id),project_id uuid references public.projects(id),client_id uuid references public.clients(id),title text not null,content text not null default '',status text not null default 'active' check(status in('active','historical','archived')),created_by uuid references auth.users(id),created_at timestamptz not null default now(),updated_at timestamptz not null default now(),archived_at timestamptz);
create table if not exists public.meetings(id uuid primary key default gen_random_uuid(),workspace_id uuid not null references public.workspaces(id),project_id uuid not null references public.projects(id),client_id uuid references public.clients(id),title text not null,scheduled_at timestamptz not null,participants text,agenda text,notes text,summary text,next_meeting_at timestamptz,created_by uuid references auth.users(id),created_at timestamptz not null default now(),updated_at timestamptz not null default now(),archived_at timestamptz);
create index if not exists notes_project on public.notes(project_id,status,updated_at desc);create index if not exists meetings_project on public.meetings(project_id,scheduled_at desc);
drop trigger if exists set_updated_at on public.notes;create trigger set_updated_at before update on public.notes for each row execute function public.set_updated_at();drop trigger if exists set_updated_at on public.meetings;create trigger set_updated_at before update on public.meetings for each row execute function public.set_updated_at();
grant select,insert,update,delete on public.notes,public.meetings to authenticated;revoke all on public.notes,public.meetings from anon;alter table public.notes enable row level security;alter table public.meetings enable row level security;
do $$declare t text;begin foreach t in array array['notes','meetings'] loop execute format('create policy %I on public.%I for select to authenticated using((select private.is_workspace_member(workspace_id)))',t||'_select',t);execute format('create policy %I on public.%I for insert to authenticated with check((select private.is_workspace_member(workspace_id,array[''owner'',''admin'',''member'']::public.workspace_role[])))',t||'_insert',t);execute format('create policy %I on public.%I for update to authenticated using((select private.is_workspace_member(workspace_id,array[''owner'',''admin'',''member'']::public.workspace_role[]))) with check((select private.is_workspace_member(workspace_id,array[''owner'',''admin'',''member'']::public.workspace_role[])))',t||'_update',t);execute format('create policy %I on public.%I for delete to authenticated using((select private.is_workspace_member(workspace_id,array[''owner'',''admin'']::public.workspace_role[])))',t||'_delete',t);end loop;end$$;
commit;
